/// Build a runner for the given preset name by filling in a test_dir over
/// the preset config — matches the minimal `[runner.<name>]` form users write.
fn runner_for(lang: &str) -> anyhow::Result<Box<dyn Runner>> {
    let cfg = RunnerConfig {
        test_dir: Some(PathBuf::from("ought/ought-gen/")),
        ..Default::default()
    };
    runners::from_config(lang, &cfg, Path::new("."))
}

