/// MUST ship with a Rust runner
///
/// The runner must include a Rust language runner that delegates to a cargo-
/// driven harness. Being a MUST clause, the runner must exist and be
/// accessible via the "rust" preset.
#[test]
fn test_runner__language_runners__must_ship_with_a_rust_runner() {
    let runner = runner_for("rust")
        .expect("rust preset must resolve into a runner — Rust runner is required");

    assert_eq!(
        runner.name(),
        "rust",
        "Rust runner must report name \"rust\""
    );

    // Because these tests are compiled and run with cargo, the cargo harness
    // is definitionally available in this environment.
    assert!(
        runner.is_available(),
        "Rust runner must report is_available() == true when cargo is on PATH \
         (this test suite is itself running under cargo)"
    );
}

